        AND c.status = #{query.status}



        AND c.status = 1



    AND c.title LIKE CONCAT('%', #{query.title}, '%')


    AND c.type = #{query.type}


    AND c.category_id = #{query.categoryId}


    AND c.tags LIKE CONCAT('%', #{query.tags}, '%')


    AND c.creator_id = #{query.creatorId}


    AND c.view_count >= #{query.minViewCount}


    AND c.view_count <= #{query.maxViewCount}


    AND c.like_count >= #{query.minLikeCount}


    AND c.like_count <= #{query.maxLikeCount}


    AND c.popularity_score >= #{query.minPopularityScore}


    AND c.popularity_score <= #{query.maxPopularityScore}


    AND c.created_time >= #{query.startTime}


    AND c.created_time <= #{query.endTime}
